    22→        _paymentService = paymentService ?? throw new ArgumentNullException(nameof(paymentService));
    23→    }
    24→
    25→    /// <summary>
    26→    /// Processes a new payment for the specified user.
    27→    /// Caller #1: PaymentController.ProcessPayment calls IPaymentService.ProcessPayment.
    28→    /// POST /api/payments
    29→    /// </summary>
    30→    public async Task<PaymentDto> ProcessPayment(Guid userId, decimal amount, string currency, string paymentMethodToken, CancellationToken cancellationToken = default)
    31→    {
    32→        var money = new Money(amount, currency);
    33→
    34→        // Caller #1: PaymentController.ProcessPayment calls ProcessPayment
    35→        var payment = await _paymentService.ProcessPayment(
    36→            userId, money, paymentMethodToken, cancellationToken);
    37→
    38→        return PaymentProfile.ToDto(payment);
    39→    }
    40→
    41→    /// <summary>
    42→    /// Retries a previously failed payment with a new or existing payment method.
    43→    /// Caller #2: PaymentController.RetryPayment calls IPaymentService.ProcessPayment.
    44→    /// POST /api/payments/retry
    45→    /// </summary>
    46→    public async Task<PaymentDto> RetryPayment(Guid userId, decimal amount, string currency, string paymentMethodToken, CancellationToken cancellationToken = default)
    47→    {
    48→        var money = new Money(amount, currency);
    49→
    50→        // Caller #2: PaymentController.RetryPayment calls ProcessPayment
    51→        var payment = await _paymentService.ProcessPayment(
    52→            userId, money, paymentMethodToken, cancellationToken);
    53→
    54→        return PaymentProfile.ToDto(payment);
    55→    }
