     5→/// <summary>
     6→/// Validates ProcessPaymentCommand instances before they reach the handler.
     7→/// Ensures all required fields are present and within acceptable ranges.
     8→/// </summary>
     9→public class ProcessPaymentValidator
    10→{
    11→    /// <summary>
    12→    /// Validates the given command and returns a list of validation errors.
    13→    /// Returns an empty list if the command is valid.
    14→    /// </summary>
    15→    public IReadOnlyList<string> Validate(ProcessPaymentCommand command)
    16→    {
    17→        var errors = new List<string>();
    18→
    19→        if (command.UserId == Guid.Empty)
    20→        {
    21→            errors.Add("UserId is required.");
    22→        }
    23→
    24→        if (command.Amount <= 0)
    25→        {
    26→            errors.Add("Amount must be greater than zero.");
    27→        }
    28→
    29→        if (command.Amount > 1_000_000m)
    30→        {
    31→            errors.Add("Amount exceeds maximum allowed value of 1,000,000.");
    32→        }
    33→
    34→        if (string.IsNullOrWhiteSpace(command.Currency))
    35→        {
    36→            errors.Add("Currency is required.");
    37→        }
    38→        else if (command.Currency.Length != 3)
    39→        {
    40→            errors.Add("Currency must be a 3-letter ISO 4217 code.");
    41→        }
    42→
    43→        if (string.IsNullOrWhiteSpace(command.PaymentMethodToken))
    44→        {
    45→            errors.Add("PaymentMethodToken is required.");
    46→        }
    47→
    48→        if (command.IdempotencyKey is not null && command.IdempotencyKey.Length > 64)
    49→        {
    50→            errors.Add("IdempotencyKey must be 64 characters or fewer.");
    51→        }
    52→
    53→        return errors.AsReadOnly();
    54→    }
    55→}
