     5→/// <summary>
     6→/// Middleware that catches unhandled exceptions and converts them to
     7→/// appropriate HTTP responses. Maps domain exceptions to HTTP status codes.
     8→/// </summary>
     9→public class ExceptionHandlerMiddleware
    10→{
    11→    private readonly Func<Task> _next;
    12→    private readonly Action<string> _logger;
    13→
    14→    /// <summary>
    15→    /// Initializes the middleware with the next delegate and logger.
    16→    /// </summary>
    17→    public ExceptionHandlerMiddleware(Func<Task> next, Action<string> logger)
    18→    {
    19→        _next = next ?? throw new ArgumentNullException(nameof(next));
    20→        _logger = logger ?? throw new ArgumentNullException(nameof(logger));
    21→    }
    22→
    23→    /// <summary>
    24→    /// Invokes the middleware, catching and handling any exceptions.
    25→    /// </summary>
    26→    public async Task InvokeAsync()
    27→    {
    28→        try
    29→        {
    30→            await _next();
    31→        }
    32→        catch (EntityNotFoundException ex)
    33→        {
    34→            _logger($"Entity not found: {ex.EntityType} with ID {ex.EntityId}");
    35→            // Return 404
    36→        }
    37→        catch (BusinessRuleException ex)
    38→        {
    39→            _logger($"Business rule violation: {ex.GetDetailedMessage()}");
    40→            // Return 422
    41→        }
    42→        catch (UnauthorizedAccessException ex)
    43→        {
    44→            _logger($"Unauthorized access: {ex.Message}");
    45→            // Return 403
    46→        }
    47→        catch (InvalidOperationException ex)
    48→        {
    49→            _logger($"Validation error: {ex.Message}");
    50→            // Return 400
    51→        }
    52→        catch (Exception ex)
    53→        {
    54→            _logger($"Unhandled exception: {ex.GetType().Name}: {ex.Message}");
    55→            // Return 500
    56→        }
    57→    }
    58→
    59→    /// <summary>
    60→    /// Maps an exception to an HTTP status code.
    61→    /// </summary>
    62→    public static int GetStatusCode(Exception exception)
    63→    {
    64→        return exception switch
    65→        {
    66→            EntityNotFoundException => 404,
    67→            BusinessRuleException => 422,
    68→            UnauthorizedAccessException => 403,
    69→            InvalidOperationException => 400,
    70→            ArgumentException => 400,
    71→            _ => 500
    72→        };
    73→    }
    74→}
