     9→/// <summary>
    10→/// Background worker that retries failed payments on a scheduled basis.
    11→/// Picks up failed payments, checks retry eligibility, and re-attempts
    12→/// the charge through the payment service.
    13→/// </summary>
    14→public class PaymentRetryWorker
    15→{
    16→    private readonly IPaymentService _paymentService;
    17→    private readonly IRepository<Payment> _paymentRepository;
    18→    private readonly INotificationService _notificationService;
    19→    private readonly int _maxRetries;
    20→
    21→    /// <summary>
    22→    /// Initializes the worker with required dependencies.
    23→    /// </summary>
    24→    public PaymentRetryWorker(
    25→        IPaymentService paymentService,
    26→        IRepository<Payment> paymentRepository,
    27→        INotificationService notificationService,
    28→        int maxRetries = 3)
    29→    {
    30→        _paymentService = paymentService ?? throw new ArgumentNullException(nameof(paymentService));
    31→        _paymentRepository = paymentRepository ?? throw new ArgumentNullException(nameof(paymentRepository));
    32→        _notificationService = notificationService ?? throw new ArgumentNullException(nameof(notificationService));
    33→        _maxRetries = maxRetries;
    34→    }
    35→
    36→    /// <summary>
    37→    /// Executes the retry cycle, processing all eligible failed payments.
    38→    /// </summary>
    39→    public async Task ExecuteAsync(CancellationToken cancellationToken = default)
    40→    {
    41→        var allPayments = await _paymentRepository.GetAllAsync(cancellationToken);
    42→        var failedPayments = allPayments
    43→            .Where(p => p.Status == PaymentStatus.Failed && p.RetryCount < _maxRetries)
    44→            .OrderBy(p => p.CreatedAt)
    45→            .ToList();
    46→
    47→        foreach (var payment in failedPayments)
    48→        {
    49→            if (cancellationToken.IsCancellationRequested)
    50→                break;
    51→
    52→            await RetryFailedPayment(payment, cancellationToken);
    53→        }
    54→    }
    55→
    56→    /// <summary>
    57→    /// Retries a single failed payment by creating a new charge attempt.
    58→    /// Caller #5: This method calls IPaymentService.ProcessPayment to retry
    59→    /// a previously failed payment transaction.
    60→    /// </summary>
    61→    public async Task RetryFailedPayment(Payment failedPayment, CancellationToken cancellationToken = default)
    62→    {
    63→        if (failedPayment.RetryCount >= _maxRetries)
    64→        {
    65→            await _notificationService.SendEmailAsync(
    66→                failedPayment.UserId,
    67→                "Payment Retry Limit Reached",
    68→                $"Your payment of {failedPayment.Amount} has failed after {_maxRetries} attempts. Please update your payment method.",
    69→                cancellationToken);
    70→            return;
    71→        }
    72→
    73→        failedPayment.IncrementRetryCount();
    74→        await _paymentRepository.SaveChangesAsync(cancellationToken);
    75→
    76→        // Caller #5: PaymentRetryWorker.RetryFailedPayment calls ProcessPayment
    77→        var retryResult = await _paymentService.ProcessPayment(
    78→            failedPayment.UserId,
    79→            failedPayment.Amount,
    80→            $"retry_token_{failedPayment.Id}",
    81→            cancellationToken);
    82→
    83→        if (retryResult.Status == PaymentStatus.Completed)
    84→        {
    85→            await _notificationService.SendEmailAsync(
    86→                failedPayment.UserId,
    87→                "Payment Retry Successful",
    88→                $"Your payment of {failedPayment.Amount} has been successfully processed on retry attempt {failedPayment.RetryCount}.",
    89→                cancellationToken);
    90→        }
    91→        else
    92→        {
    93→            await _notificationService.SendEmailAsync(
    94→                failedPayment.UserId,
    95→                "Payment Retry Failed",
    96→                $"Retry attempt {failedPayment.RetryCount}/{_maxRetries} for your payment of {failedPayment.Amount} has failed.",
