     8→{
     9→    /// <summary>
    10→    /// Gets the decimal amount.
    11→    /// </summary>
    12→    public decimal Amount { get; }
    13→
    14→    /// <summary>
    15→    /// Gets the ISO 4217 currency code (e.g. "USD", "EUR").
    16→    /// </summary>
    17→    public string Currency { get; }
    18→
    19→    /// <summary>
    20→    /// Creates a new Money value with the specified amount and currency.
    21→    /// </summary>
    22→    public Money(decimal amount, string currency)
    23→    {
    24→        if (string.IsNullOrWhiteSpace(currency))
    25→            throw new ArgumentException("Currency code is required.", nameof(currency));
    26→
    27→        Amount = amount;
    28→        Currency = currency.ToUpperInvariant();
    29→    }
    30→
    31→    /// <summary>
    32→    /// Adds two Money values. Both must share the same currency.
    33→    /// </summary>
    34→    public Money Add(Money other)
    35→    {
    36→        EnsureSameCurrency(other);
    37→        return new Money(Amount + other.Amount, Currency);
    38→    }
    39→
    40→    /// <summary>
    41→    /// Subtracts another Money value. Both must share the same currency.
    42→    /// </summary>
    43→    public Money Subtract(Money other)
    44→    {
    45→        EnsureSameCurrency(other);
    46→        return new Money(Amount - other.Amount, Currency);
    47→    }
    48→
    49→    /// <summary>
    50→    /// Multiplies this Money value by a scalar factor.
    51→    /// </summary>
    52→    public Money Multiply(decimal factor)
    53→    {
    54→        return new Money(Amount * factor, Currency);
    55→    }
    56→
    57→    /// <summary>
    58→    /// Returns a zero-amount Money value in the specified currency.
    59→    /// </summary>
    60→    public static Money Zero(string currency) => new(0m, currency);
    61→
    62→    /// <summary>
    63→    /// Determines whether this Money is equal to another.
    64→    /// </summary>
    65→    public bool Equals(Money? other)
    66→    {
    67→        if (other is null) return false;
    68→        return Amount == other.Amount && Currency == other.Currency;
    69→    }
    70→
    71→    /// <inheritdoc />
    72→    public override bool Equals(object? obj) => Equals(obj as Money);
    73→
    74→    /// <inheritdoc />
    75→    public override int GetHashCode() => HashCode.Combine(Amount, Currency);
    76→
    77→    /// <inheritdoc />
